"""Test what the base info method would return."""

import fsspec
from fsspec.spec import AbstractFileSystem
from fsspec.archive import AbstractArchiveFileSystem
import tempfile
import zipfile
from io import BytesIO

def create_test_zip():
    """Create a test zip file in memory."""
    data = {"file1.txt": b"content1", "file2.txt": b"content2", "subdir/file3.txt": b"content3"}

    # Create zip in memory
    buffer = BytesIO()
    with zipfile.ZipFile(buffer, 'w') as zf:
        for filename, content in data.items():
            zf.writestr(filename, content)

    buffer.seek(0)
    return buffer

class TestArchiveFS(AbstractArchiveFileSystem):
    """Test filesystem to check base info method behavior."""

    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.dir_cache = {
            "file1.txt": {"name": "file1.txt", "size": 8, "type": "file"},
            "file2.txt": {"name": "file2.txt", "size": 8, "type": "file"},
            "subdir/": {"name": "subdir/", "size": 0, "type": "directory"},
        }

    def _get_dirs(self):
        pass  # Already initialized

    def ls(self, path, detail=False, **kwargs):
        if path == "" or path == "/":
            if detail:
                return list(self.dir_cache.values())
            else:
                return [item["name"] for item in self.dir_cache.values()]
        return []

def test_base_info():
    """Test the base info method behavior."""
    print("Creating test filesystem...")
    fs = TestArchiveFS()

    print("\nTesting base info method on '/':")
    try:
        # Temporarily remove the overridden info method to test base method
        original_info = AbstractArchiveFileSystem.info
        delattr(AbstractArchiveFileSystem, 'info')

        info_result = fs.info("/")
        print(f"SUCCESS: base info('/') = {info_result}")

        # Restore the method
        AbstractArchiveFileSystem.info = original_info
    except Exception as e:
        print(f"ERROR: base info('/') failed: {e}")
        # Restore the method even if it failed
        if not hasattr(AbstractArchiveFileSystem, 'info'):
            AbstractArchiveFileSystem.info = original_info

if __name__ == "__main__":
    test_base_info()

