    buffer = BytesIO()
    with zipfile.ZipFile(buffer, 'w') as zf:
        for filename, content in data.items():
            zf.writestr(filename, content)

    buffer.seek(0)
    return buffer

def test_edge_cases():
    """Test edge cases."""
    print("Creating test zip...")
    zip_buffer = create_test_zip()

    print("Creating zip filesystem...")
    fs = fsspec.filesystem("zip", fo=zip_buffer)

    print("\nTesting info('/'):")
    try:
        result = fs.info("/")
        print(f"SUCCESS: {result}")
    except Exception as e:
        print(f"ERROR: {e}")

    print("\nTesting info(''):")
    try:
        result = fs.info("")
        print(f"SUCCESS: {result}")
    except Exception as e:
        print(f"ERROR: {e}")

    print("\nTesting info('subdir/'):")
    try:
        result = fs.info("subdir/")
        print(f"SUCCESS: {result}")
    except Exception as e:
        print(f"ERROR: {e}")

    print("\nTesting info('subdir'):")
    try:
        result = fs.info("subdir")
        print(f"SUCCESS: {result}")
    except Exception as e:
        print(f"ERROR: {e}")

    print("\nTesting info('nonexistent'):")
    try:
        result = fs.info("nonexistent")
        print(f"SUCCESS: {result}")
    except Exception as e:
        print(f"ERROR (expected): {e}")

    print("\nTesting info('file1.txt'):")
    try:
        result = fs.info("file1.txt")
        print(f"SUCCESS: {result}")
    except Exception as e:
        print(f"ERROR: {e}")

if __name__ == "__main__":
    test_edge_cases()

